import React, { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Send, Paperclip, GitPullRequest, CheckCircle, XCircle, Clock, Trash2, RotateCcw, Plus } from 'lucide-react';
import toast from 'react-hot-toast';
import { tasksApi, commentsApi, reviewsApi, attachmentsApi, usersApi } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { StatusBadge, PriorityBadge } from '../components/common/Badge';
import Avatar from '../components/common/Avatar';
import Modal from '../components/common/Modal';
import StarRating from '../components/common/StarRating';
import TimerWidget from '../components/common/TimerWidget';
import { getStatusLabel, getStatusClass, formatRelativeTime, formatDate, formatBytes, formatSeconds, getErrorMessage, isOverdue, isDueSoon } from '../utils/helpers';

const STATUSES = ['TODO','IN_PROGRESS','REVIEW','DONE'];

export default function TaskDetailPage() {
  const { projectId, taskId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [task, setTask]           = useState(null);
  const [comments, setComments]   = useState([]);
  const [reviews, setReviews]     = useState([]);
  const [attachments, setAttachments] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [tab, setTab]             = useState('comments');
  const [commentText, setCommentText] = useState('');
  const [sending, setSending]     = useState(false);
  // Review state
  const [githubPR, setGithubPR]   = useState('');
  const [reviewerSearch, setReviewerSearch] = useState('');
  const [reviewers, setReviewers] = useState([]);
  const [minApprovals, setMinApprovals] = useState(1);
  const [reviewComment, setReviewComment] = useState('');
  const [codeQuality, setCodeQuality] = useState(0);
  const [readability, setReadability] = useState(0);
  const [showVersions, setShowVersions] = useState(false);
  const [versions, setVersions]   = useState([]);

  const load = useCallback(async () => {
    try {
      const [tRes, cRes, rRes, aRes] = await Promise.all([
        tasksApi.get(projectId, taskId),
        commentsApi.list(projectId, taskId),
        reviewsApi.list(projectId, taskId),
        attachmentsApi.list(projectId, taskId),
      ]);
      setTask(tRes.data.task);
      setComments(cRes.data.comments||[]);
      setReviews(rRes.data.reviews||[]);
      setAttachments(aRes.data.attachments||[]);
    } catch { toast.error('Failed to load task'); }
    finally { setLoading(false); }
  }, [projectId, taskId]);

  useEffect(()=>{ load(); },[load]);

  const handleStatusChange = async (status) => {
    try {
      const {data} = await tasksApi.updateStatus(projectId,taskId,status);
      setTask(data.task);
      toast.success(`Status → ${getStatusLabel(status)}`);
    } catch(err) { toast.error(getErrorMessage(err)); }
  };

  const handleComment = async (e) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    setSending(true);
    try {
      const {data} = await commentsApi.create(projectId,taskId,{content:commentText});
      setComments(prev=>[data.comment,...prev]);
      setCommentText('');
    } catch(err) { toast.error(getErrorMessage(err)); }
    finally { setSending(false); }
  };

  const handleDeleteComment = async (id) => {
    try { await commentsApi.delete(projectId,taskId,id); setComments(prev=>prev.filter(c=>c._id!==id)); toast.success('Deleted'); }
    catch(err) { toast.error(getErrorMessage(err)); }
  };

  const handleSubmitReview = async () => {
    try {
      const {data} = await reviewsApi.submit(projectId,taskId,{
        githubPR, reviewerIds:reviewers.map(r=>r._id), minApprovals,
      });
      setReviews(prev=>[data.review,...prev]);
      setTask(data.task);
      toast.success('Submitted for review');
    } catch(err) { toast.error(getErrorMessage(err)); }
  };

  const handleReviewAction = async (reviewId, action) => {
    try {
      const {data} = await reviewsApi.action(projectId,taskId,reviewId,{action,comment:reviewComment,codeQuality,readability});
      setReviews(prev=>prev.map(r=>r._id===reviewId?data.review:r));
      setTask(data.task);
      setReviewComment(''); setCodeQuality(0); setReadability(0);
      toast.success(action==='APPROVED'?'✅ Approved':'🔄 Changes requested');
    } catch(err) { toast.error(getErrorMessage(err)); }
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0]; if (!file) return;
    const frm = new FormData(); frm.append('file',file);
    try {
      const {data} = await attachmentsApi.upload(projectId,taskId,frm);
      setAttachments(prev=>[data.attachment,...prev]); toast.success('Uploaded');
    } catch(err) { toast.error(getErrorMessage(err)); }
  };

  const handleDeleteAttachment = async (id) => {
    try { await attachmentsApi.delete(projectId,taskId,id); setAttachments(prev=>prev.filter(a=>a._id!==id)); toast.success('Deleted'); }
    catch(err) { toast.error(getErrorMessage(err)); }
  };

  const handleRestore = async () => {
    try { await tasksApi.restore(projectId,taskId); setTask(t=>({...t,isDeleted:false})); toast.success('Task restored'); }
    catch(err) { toast.error(getErrorMessage(err)); }
  };

  const loadVersions = async () => {
    try { const {data} = await tasksApi.versions(projectId,taskId); setVersions(data.versions||[]); setShowVersions(true); }
    catch(err) { toast.error(getErrorMessage(err)); }
  };

  const searchReviewers = async (q) => {
    setReviewerSearch(q);
    if (q.length<2) return;
    // Uses the user search endpoint
    const {data} = await usersApi.search(q);
    // We show results in a simple dropdown (simplified here)
  };

  if (loading) return <div className="spinner-center"><div className="spinner spinner-lg"/></div>;
  if (!task) return <div className="empty-state"><p>Task not found</p></div>;

  const pendingReview = reviews.find(r=>r.status==='PENDING');
  const overdue = isOverdue(task.dueDate) && task.status!=='DONE';
  const dueSoon = isDueSoon(task.dueDate) && task.status!=='DONE';

  return (
    <div style={{maxWidth:960,margin:'0 auto'}}>
      <button className="btn btn-ghost btn-sm" style={{marginBottom:'1rem'}} onClick={()=>navigate(`/projects/${projectId}`)}>
        <ArrowLeft size={14}/> Back to project
      </button>

      {task.isDeleted && (
        <div className="alert alert-warning" style={{marginBottom:'1rem'}}>
          <Trash2 size={14}/> This task has been deleted.
          <button className="btn btn-secondary btn-sm" style={{marginLeft:'auto'}} onClick={handleRestore}>
            <RotateCcw size={12}/> Restore
          </button>
        </div>
      )}

      {overdue && <div className="alert alert-danger" style={{marginBottom:'1rem'}}><Clock size={14}/> This task is overdue!</div>}
      {dueSoon && !overdue && <div className="alert alert-warning" style={{marginBottom:'1rem'}}><Clock size={14}/> Due within 24 hours</div>}

      {/* Dependency warnings */}
      {task.dependencies?.filter(d=>d.status!=='DONE').length > 0 && (
        <div className="alert alert-info" style={{marginBottom:'1rem'}}>
          <GitPullRequest size={14}/>
          Blocked by: {task.dependencies.filter(d=>d.status!=='DONE').map(d=>(
            <span key={d._id} className="dep-badge dep-blocked" style={{marginLeft:6}}>#{d.taskNumber} {d.title}</span>
          ))}
        </div>
      )}

      <div style={{display:'grid',gridTemplateColumns:'1fr 268px',gap:'1.5rem',alignItems:'start'}}>
        {/* Main */}
        <div>
          <div className="card" style={{marginBottom:'1rem'}}>
            <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:10}}>
              <span className="mono text-xs text-3">#{task.taskNumber}</span>
              <StatusBadge status={task.status}/>
              <PriorityBadge priority={task.priority}/>
            </div>
            <h2 style={{fontSize:'1.15rem',fontWeight:700,letterSpacing:'-.01em',marginBottom:'.75rem',lineHeight:1.35}}>
              {task.title}
            </h2>
            {task.description
              ? <p style={{color:'var(--text-2)',fontSize:'.9rem',lineHeight:1.7,whiteSpace:'pre-wrap'}}>{task.description}</p>
              : <p style={{color:'var(--text-3)',fontSize:'.875rem',fontStyle:'italic'}}>No description provided.</p>
            }
            {task.githubPR && (
              <a href={task.githubPR} target="_blank" rel="noreferrer"
                style={{display:'inline-flex',alignItems:'center',gap:6,marginTop:'1rem',fontSize:'.82rem',color:'var(--primary)',fontWeight:500}}>
                <GitPullRequest size={14}/> {task.githubPR}
              </a>
            )}
            {/* Timer */}
            <div style={{marginTop:'1rem',paddingTop:'1rem',borderTop:'1px solid var(--border)'}}>
              <p className="form-label" style={{marginBottom:6}}>Time Tracking</p>
              <TimerWidget projectId={projectId} taskId={taskId} totalTime={task.totalTime||0}/>
            </div>
          </div>

          {/* Tabs */}
          <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'1rem'}}>
            <div className="tabs">
              {['comments','reviews','attachments','history'].map(t=>(
                <button key={t} className={`tab-btn${tab===t?' active':''}`} onClick={()=>setTab(t)}>
                  {t.charAt(0).toUpperCase()+t.slice(1)}
                  {t==='comments'&&comments.length>0&&` (${comments.length})`}
                  {t==='attachments'&&attachments.length>0&&` (${attachments.length})`}
                </button>
              ))}
            </div>
            <button className="btn btn-ghost btn-sm" onClick={loadVersions}>
              <Clock size={13}/> Versions
            </button>
          </div>

          {/* Comments */}
          {tab==='comments' && (
            <div>
              <form onSubmit={handleComment} style={{display:'flex',gap:'.75rem',marginBottom:'1.25rem'}}>
                <Avatar name={user?.name}/>
                <div style={{flex:1}}>
                  <textarea className="input" rows={2} placeholder="Write a comment…"
                    value={commentText} onChange={e=>setCommentText(e.target.value)}/>
                  <div style={{display:'flex',justifyContent:'flex-end',marginTop:6}}>
                    <button type="submit" className="btn btn-primary btn-sm" disabled={sending||!commentText.trim()}>
                      {sending?<span className="spinner"/>:<><Send size={12}/> Post</>}
                    </button>
                  </div>
                </div>
              </form>
              <div style={{display:'flex',flexDirection:'column',gap:'.75rem'}}>
                {comments.map(c=>(
                  <div key={c._id} className="comment-item">
                    <Avatar name={c.author?.name} size="sm"/>
                    <div className="comment-body">
                      <div className="comment-meta">
                        <div style={{display:'flex',alignItems:'center',gap:8}}>
                          <span className="comment-author">{c.author?.name}</span>
                          <span className="comment-time">{formatRelativeTime(c.createdAt)}</span>
                          {c.isEdited&&<span className="text-xs text-3">(edited)</span>}
                        </div>
                        {c.author?._id===user?._id&&(
                          <button className="btn btn-ghost btn-icon-sm" onClick={()=>handleDeleteComment(c._id)}>
                            <Trash2 size={12}/>
                          </button>
                        )}
                      </div>
                      <p className="comment-text">{c.content}</p>
                    </div>
                  </div>
                ))}
                {comments.length===0&&<div className="empty-state" style={{padding:'2rem'}}><p>No comments yet</p></div>}
              </div>
            </div>
          )}

          {/* Reviews */}
          {tab==='reviews' && (
            <div>
              {task.status!=='REVIEW'&&task.status!=='DONE'&&(
                <div className="card" style={{marginBottom:'1rem'}}>
                  <h3 style={{fontSize:'.9rem',fontWeight:700,marginBottom:'.75rem'}}>Submit for Code Review</h3>
                  <div className="form-group">
                    <label className="form-label">GitHub PR URL</label>
                    <input className="input" placeholder="https://github.com/…/pull/42" value={githubPR} onChange={e=>setGithubPR(e.target.value)}/>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Min. Approvals Required</label>
                    <input className="input" type="number" min={1} max={10} value={minApprovals} onChange={e=>setMinApprovals(Number(e.target.value))} style={{width:80}}/>
                  </div>
                  <button className="btn btn-primary btn-sm" onClick={handleSubmitReview}>
                    <GitPullRequest size={14}/> Submit for Review
                  </button>
                </div>
              )}

              {/* Pending review action */}
              {pendingReview&&(
                <div className="card" style={{marginBottom:'1rem',borderColor:'var(--purple)',borderWidth:1.5}}>
                  <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'.75rem'}}>
                    <h3 style={{fontSize:'.9rem',fontWeight:700,color:'var(--purple)'}}>🔍 Review In Progress</h3>
                    <span className="text-xs text-3">
                      {pendingReview.reviewers?.filter(r=>r.status==='APPROVED').length}/{pendingReview.minApprovals} approvals needed
                    </span>
                  </div>
                  {/* Reviewer statuses */}
                  {pendingReview.reviewers?.length>0&&(
                    <div style={{display:'flex',flexWrap:'wrap',gap:6,marginBottom:'.75rem'}}>
                      {pendingReview.reviewers.map(r=>(
                        <div key={r._id} style={{display:'flex',alignItems:'center',gap:5,padding:'3px 10px',borderRadius:99,fontSize:'.75rem',fontWeight:500,
                          background:r.status==='APPROVED'?'var(--green-bg)':r.status==='CHANGES_REQUESTED'?'var(--red-bg)':'var(--bg-subtle)',
                          color:r.status==='APPROVED'?'var(--green-text)':r.status==='CHANGES_REQUESTED'?'var(--red-text)':'var(--text-2)'}}>
                          <Avatar name={r.user?.name} size="sm"/>
                          {r.user?.name} · {r.status.replace('_',' ')}
                          {r.avgScore&&<span>· ⭐{r.avgScore.toFixed(1)}</span>}
                        </div>
                      ))}
                    </div>
                  )}
                  <StarRating label="Code Quality" value={codeQuality} onChange={setCodeQuality}/>
                  <StarRating label="Readability"  value={readability}  onChange={setReadability}/>
                  <div className="form-group">
                    <label className="form-label">Review Comment</label>
                    <textarea className="input" rows={2} placeholder="Your review feedback…"
                      value={reviewComment} onChange={e=>setReviewComment(e.target.value)}/>
                  </div>
                  <div style={{display:'flex',gap:8}}>
                    <button className="btn btn-success btn-sm" onClick={()=>handleReviewAction(pendingReview._id,'APPROVED')}>
                      <CheckCircle size={14}/> Approve
                    </button>
                    <button className="btn btn-danger btn-sm" onClick={()=>handleReviewAction(pendingReview._id,'CHANGES_REQUESTED')}>
                      <XCircle size={14}/> Request Changes
                    </button>
                  </div>
                </div>
              )}

              {/* Review history */}
              {reviews.map(r=>(
                <div key={r._id} className="card" style={{marginBottom:'.75rem',padding:0,overflow:'hidden'}}>
                  <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'.75rem 1rem',background:'var(--bg-subtle)',borderBottom:'1px solid var(--border)'}}>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <Avatar name={r.submittedBy?.name} size="sm"/>
                      <span className="text-sm fw-600">{r.submittedBy?.name}</span>
                    </div>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      {r.overallScore&&<span className="text-xs text-2">⭐ Avg {r.overallScore.toFixed(1)}/5</span>}
                      <StatusBadge status={r.status==='APPROVED'?'DONE':r.status==='PENDING'?'REVIEW':'IN_PROGRESS'}/>
                    </div>
                  </div>
                  {r.history?.map((h,i)=>(
                    <div key={i} style={{display:'flex',gap:10,padding:'.65rem 1rem',borderBottom:'1px solid var(--border)'}}>
                      <Avatar name={h.reviewer?.name} size="sm"/>
                      <div>
                        <span className="text-sm fw-600">{h.action.replace('_',' ')}</span>
                        {h.comment&&<p className="text-sm text-2" style={{marginTop:2}}>{h.comment}</p>}
                        <p className="text-xs text-3" style={{marginTop:2}}>{formatRelativeTime(h.timestamp)}</p>
                      </div>
                    </div>
                  ))}
                </div>
              ))}
              {reviews.length===0&&<div className="empty-state" style={{padding:'2rem'}}><p>No reviews yet</p></div>}
            </div>
          )}

          {/* Attachments */}
          {tab==='attachments'&&(
            <div>
              <label className="btn btn-secondary" style={{cursor:'pointer',marginBottom:'1rem',display:'inline-flex'}}>
                <Paperclip size={14}/> Upload File
                <input type="file" style={{display:'none'}} onChange={handleFileUpload}/>
              </label>
              <div style={{display:'flex',flexDirection:'column',gap:'.5rem'}}>
                {attachments.map(a=>(
                  <div key={a._id} className="card" style={{padding:'.75rem',display:'flex',alignItems:'center',gap:12}}>
                    <Paperclip size={16} style={{color:'var(--text-3)',flexShrink:0}}/>
                    <div style={{flex:1,minWidth:0}}>
                      <p className="text-sm fw-600 truncate">{a.originalName}</p>
                      <p className="text-xs text-3">{formatBytes(a.size)} · {a.uploadedBy?.name} · {formatRelativeTime(a.createdAt)}</p>
                    </div>
                    <button className="btn btn-ghost btn-icon-sm" onClick={()=>handleDeleteAttachment(a._id)}>
                      <Trash2 size={13}/>
                    </button>
                  </div>
                ))}
                {attachments.length===0&&<div className="empty-state" style={{padding:'2rem'}}><p>No attachments</p></div>}
              </div>
            </div>
          )}

          {/* History */}
          {tab==='history'&&(
            <div>
              {(task.statusHistory||[]).map((h,i)=>(
                <div key={i} style={{display:'flex',alignItems:'center',gap:10,padding:'.65rem 0',borderBottom:'1px solid var(--border)'}}>
                  <Clock size={13} style={{color:'var(--text-3)',flexShrink:0}}/>
                  <span className="text-sm text-2">
                    <strong style={{color:'var(--text)'}}>{h.changedBy?.name||'Someone'}</strong>
                    {' '}changed status from{' '}
                    <StatusBadge status={h.from}/>{' '}to{' '}<StatusBadge status={h.to}/>
                  </span>
                  <span className="text-xs text-3" style={{marginLeft:'auto'}}>{formatRelativeTime(h.changedAt)}</span>
                </div>
              ))}
              {(!task.statusHistory||task.statusHistory.length===0)&&(
                <div className="empty-state" style={{padding:'2rem'}}><p>No status changes yet</p></div>
              )}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div style={{display:'flex',flexDirection:'column',gap:'.75rem'}}>
          <div className="card">
            <div style={{marginBottom:'1rem'}}>
              <p className="form-label" style={{marginBottom:6}}>Status</p>
              <select className="input" value={task.status} onChange={e=>handleStatusChange(e.target.value)}>
                {STATUSES.map(s=><option key={s} value={s}>{getStatusLabel(s)}</option>)}
              </select>
            </div>
            <div style={{marginBottom:'1rem'}}>
              <p className="form-label" style={{marginBottom:6}}>Priority</p>
              <PriorityBadge priority={task.priority}/>
            </div>
            <div style={{marginBottom:'1rem'}}>
              <p className="form-label" style={{marginBottom:6}}>Reporter</p>
              <div style={{display:'flex',alignItems:'center',gap:7}}>
                <Avatar name={task.reporter?.name} size="sm"/>
                <span className="text-sm text-2">{task.reporter?.name}</span>
              </div>
            </div>
            {task.assignee&&(
              <div style={{marginBottom:'1rem'}}>
                <p className="form-label" style={{marginBottom:6}}>Assignee</p>
                <div style={{display:'flex',alignItems:'center',gap:7}}>
                  <Avatar name={task.assignee?.name} size="sm"/>
                  <span className="text-sm text-2">{task.assignee?.name}</span>
                </div>
              </div>
            )}
            {task.dueDate&&(
              <div>
                <p className="form-label" style={{marginBottom:4}}>Due Date</p>
                <span className="text-sm" style={{color:overdue?'var(--red-text)':dueSoon?'var(--yellow-text)':'var(--text-2)'}}>
                  {formatDate(task.dueDate)}
                </span>
              </div>
            )}
          </div>

          {/* Dependencies */}
          {task.dependencies?.length>0&&(
            <div className="card">
              <p className="form-label" style={{marginBottom:8}}>Dependencies</p>
              <div style={{display:'flex',flexDirection:'column',gap:5}}>
                {task.dependencies.map(d=>(
                  <div key={d._id} className={`dep-badge ${d.status==='DONE'?'dep-done':'dep-blocked'}`}
                    style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'4px 8px',borderRadius:6}}>
                    <span>#{d.taskNumber} {d.title?.slice(0,28)}</span>
                    <StatusBadge status={d.status}/>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="card">
            <div style={{display:'flex',justifyContent:'space-between',marginBottom:4}}>
              <p className="form-label">Created</p>
              <span className="text-xs text-3">{formatRelativeTime(task.createdAt)}</span>
            </div>
            <div style={{display:'flex',justifyContent:'space-between'}}>
              <p className="form-label">Updated</p>
              <span className="text-xs text-3">{formatRelativeTime(task.updatedAt)}</span>
            </div>
            {task.totalTime>0&&(
              <div style={{marginTop:8,paddingTop:8,borderTop:'1px solid var(--border)'}}>
                <p className="form-label">Total Time</p>
                <span className="text-sm fw-600" style={{color:'var(--primary)'}}>{formatSeconds(task.totalTime)}</span>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Version History Modal */}
      <Modal open={showVersions} onClose={()=>setShowVersions(false)} title="Version History" size="lg">
        {versions.length===0
          ? <div className="empty-state"><p>No previous versions</p></div>
          : versions.map((v,i)=>(
            <div key={v._id||i} style={{padding:'.75rem 0',borderBottom:'1px solid var(--border)'}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:6}}>
                <span className="text-sm fw-600">Version {v.version}</span>
                <div style={{display:'flex',alignItems:'center',gap:8}}>
                  {v.updatedBy&&<div style={{display:'flex',alignItems:'center',gap:5}}><Avatar name={v.updatedBy.name} size="sm"/><span className="text-xs text-2">{v.updatedBy.name}</span></div>}
                  <span className="text-xs text-3">{formatRelativeTime(v.updatedAt)}</span>
                </div>
              </div>
              {v.changeNote&&<p className="text-sm text-2" style={{marginBottom:6}}>{v.changeNote}</p>}
              <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
                <span className="tag">Status: {v.snapshot?.status}</span>
                <span className="tag">Priority: {v.snapshot?.priority}</span>
                {v.snapshot?.title&&<span className="tag truncate" style={{maxWidth:160}}>"{v.snapshot.title}"</span>}
              </div>
            </div>
          ))
        }
      </Modal>
    </div>
  );
}
